prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT (COUNT(DISTINCT ?path) AS ?executionPathCount) WHERE {
  {
    SELECT DISTINCT ?path WHERE {
      ?model tai:normalizedId "3d0f07f9b84c4e31bbca562f472c8885" .
      ?defs tai:belongsTo ?model .
      ?choreo a bboExt:Choreography ;
              tai:belongsTo ?defs .

      # A (simple) execution path is approximated as a sequence of nodes following SequenceFlows
      # until an EndEvent is reached. We encode the path by concatenating visited node URIs.
      # This query enumerates paths up to a bounded length to keep the search finite.
      {
        SELECT ?path WHERE {
          ?start a bboExt:StartEvent ;
                  tai:belongsTo ?choreo ;
                  bbo:name ?startName .

          # Build a bounded path of nodes via outgoing SequenceFlows
          {
            SELECT ?start ?n1 ?n2 ?n3 ?n4 ?nEnd WHERE {
              VALUES ?maxLen { 6 }
              ?start (^bbo:has_sourceRef)/bbo:has_targetRef* ?nEnd .
              ?nEnd a bboExt:EndEvent ; tai:belongsTo ?choreo .

              # Use a small fixed hop pattern to create a stable path id.
              OPTIONAL { ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?n1 . }
              OPTIONAL { ?n1 ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?n2 . }
              OPTIONAL { ?n2 ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?n3 . }
              OPTIONAL { ?n3 ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?n4 . }

              # fallback bindings if missing hops
              BIND(COALESCE(?n1, ?start) AS ?b1)
              BIND(COALESCE(?n2, ?b1) AS ?b2)
              BIND(COALESCE(?n3, ?b2) AS ?b3)
              BIND(COALESCE(?n4, ?b3) AS ?b4)

              BIND(CONCAT(STR(?start),"->",STR(?b1),"->",STR(?b2),"->",STR(?b3),"->",STR(?b4),"->",STR(?nEnd)) AS ?path)
            } LIMIT 1000
          }
        }
      }
    }
  }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelId ?choreo ?start ?startName ?end ?endName WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId ?modelId ;
         tai:belongsTo ?org .
  FILTER(?modelId = "3d0f07f9b84c4e31bbca562f472c8885")

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  OPTIONAL {
    ?start a bboExt:StartEvent ;
           tai:belongsTo ?choreo .
    OPTIONAL { ?start bbo:name ?startName . }
  }
  OPTIONAL {
    ?end a bboExt:EndEvent ;
         tai:belongsTo ?choreo .
    OPTIONAL { ?end bbo:name ?endName . }
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?origId ?normId ?org WHERE {
  ?model a bboExt:Model ;
         tai:belongsTo ?org .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  FILTER(
    STR(?origId) = "3d0f07f9b84c4e31bbca562f472c8885" ||
    STR(?normId) = "3d0f07f9b84c4e31bbca562f472c8885" ||
    STR(?model) = "http://www.onto-bpo.eu/ontologies/sap-sam/" || STR("")
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT (COUNT(DISTINCT ?pathKey) AS ?executionPathCount) WHERE {
  {
    SELECT DISTINCT ?pathKey WHERE {
      # model with the given originalId
      ?model a bboExt:Model ;
             tai:originalId "3d0f07f9b84c4e31bbca562f472c8885" .
      ?defs tai:belongsTo ?model .
      ?choreo a bboExt:Choreography ;
              tai:belongsTo ?defs .

      ?start a bboExt:StartEvent ;
             tai:belongsTo ?choreo .

      # bounded simple path encoding by alternating: node -> (outgoing sequence flow) -> next node
      # We use a bounded length to avoid infinite enumeration in cyclic graphs.
      VALUES ?maxHops { 12 }

      ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?end .
      ?end a bboExt:EndEvent ; tai:belongsTo ?choreo .

      # Create a bounded representation by sampling a mid-node chain for hashing.
      # This is an approximation of distinct execution paths.
      OPTIONAL { ?start ((^bbo:has_sourceRef)/bbo:has_targetRef){1} ?n1 . }
      OPTIONAL { ?start ((^bbo:has_sourceRef)/bbo:has_targetRef){2} ?n2 . }
      OPTIONAL { ?start ((^bbo:has_sourceRef)/bbo:has_targetRef){3} ?n3 . }
      OPTIONAL { ?start ((^bbo:has_sourceRef)/bbo:has_targetRef){4} ?n4 . }
      OPTIONAL { ?start ((^bbo:has_sourceRef)/bbo:has_targetRef){5} ?n5 . }
      OPTIONAL { ?start ((^bbo:has_sourceRef)/bbo:has_targetRef){6} ?n6 . }
      OPTIONAL { ?start ((^bbo:has_sourceRef)/bbo:has_targetRef){7} ?n7 . }
      OPTIONAL { ?start ((^bbo:has_sourceRef)/bbo:has_targetRef){8} ?n8 . }
      OPTIONAL { ?start ((^bbo:has_sourceRef)/bbo:has_targetRef){9} ?n9 . }
      OPTIONAL { ?start ((^bbo:has_sourceRef)/bbo:has_targetRef){10} ?n10 . }
      OPTIONAL { ?start ((^bbo:has_sourceRef)/bbo:has_targetRef){11} ?n11 . }

      BIND(COALESCE(?n1, ?start) AS ?b1)
      BIND(COALESCE(?n2, ?b1) AS ?b2)
      BIND(COALESCE(?n3, ?b2) AS ?b3)
      BIND(COALESCE(?n4, ?b3) AS ?b4)
      BIND(COALESCE(?n5, ?b4) AS ?b5)
      BIND(COALESCE(?n6, ?b5) AS ?b6)
      BIND(COALESCE(?n7, ?b6) AS ?b7)
      BIND(COALESCE(?n8, ?b7) AS ?b8)
      BIND(COALESCE(?n9, ?b8) AS ?b9)
      BIND(COALESCE(?n10, ?b9) AS ?b10)
      BIND(COALESCE(?n11, ?b10) AS ?b11)

      # Path key based on start, end and sampled intermediate nodes
      BIND(CONCAT(STR(?start),"|",STR(?end),"|",
                  STR(?b1),"/",STR(?b2),"/",STR(?b3),"/",STR(?b4),"/",
                  STR(?b5),"/",STR(?b6),"/",STR(?b7),"/",STR(?b8),"/",
                  STR(?b9),"/",STR(?b10),"/",STR(?b11)) AS ?pathKey)
    } LIMIT 20000
  }
}
